// src/App.js
import React, { useState } from 'react';
import { AppProvider } from './context/AppContext';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import ApplyLeave from './pages/ApplyLeave';
import LeaveRequests from './pages/LeaveRequests';
import MyLeaves from './pages/MyLeaves';
import TimetablePage from './pages/TimetablePage';
import StaffPage from './pages/StaffPage';
import Home from './pages/Home';
im
import { useApp } from './context/AppContext';

function AppContent() {
  const [activePage, setActivePage] = useState('Dashboard');
  const { currentUser } = useApp();

  const renderPage = () => {
    switch (activePage) {
      case 'Dashboard': return <Dashboard setActivePage={setActivePage} />;
      case 'Apply Leave': return <ApplyLeave setActivePage={setActivePage} />;
      case 'Leave Requests': return <LeaveRequests setActivePage={setActivePage}/>;
      case 'My Leaves': return <MyLeaves setActivePage={setActivePage} />;
      case 'Timetable': return <TimetablePage />;
      case 'Staff': return <StaffPage />;
      case 'Home': return <Home />;
      default: return <Dashboard setActivePage={setActivePage} />;
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f0f4f8', fontFamily: "'Segoe UI', system-ui, sans-serif" }}>
      <Navbar activePage={activePage} setActivePage={setActivePage} />
      <main style={{ minHeight: 'calc(100vh - 64px)' }}>
        {renderPage()}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
}
